using UnityEngine; public class FoxCamera : MonoBehaviour { public float lookSpeed = 2.0f; public float bobSpeed = 0.18f; public float bobAmount = 0.2f; private Camera playerCamera; private Vector3 originalCameraPosition; private float timer = 0; void Start() { playerCamera = GetComponent<Camera>(); originalCameraPosition = playerCamera.transform.localPosition; } void Update() { float mouseX = Input.GetAxis("Mouse X") * lookSpeed; float mouseY = Input.GetAxis("Mouse Y") * lookSpeed; transform.localRotation *= Quaternion.Euler(-mouseY, mouseX, 0); if (Input.GetAxis("Vertical") != 0 || Input.GetAxis("Horizontal") != 0) { timer += Time.deltaTime * bobSpeed; float x = Mathf.Cos(timer) * bobAmount; float y = Mathf.Sin(timer) * bobAmount; playerCamera.transform.localPosition = new Vector3(originalCameraPosition.x + x, originalCameraPosition.y + y, originalCameraPosition.z); } else { playerCamera.transform.localPosition = originalCameraPosition; timer = 0; } } }